<script setup lang="ts">/* EditNode — 图像编辑(隐藏) */import { Handle, Position } from '@vue-flow/core';import { useCanvasStore } from '@/stores/canvasStore'
const p=defineProps<{id:string;data:any;selected?:boolean}>();const cs=useCanvasStore()
function run(){window.dispatchEvent(new CustomEvent('jc-canvas-run-node',{detail:p.id}))}</script>
<template><div class="x" :class="{sel:selected}" :style="{borderColor:selected?'#94a3b8':'var(--border)'}"><Handle type="target" :position="Position.Left" :style="{background:'#94a3b8',width:10,height:10,border:'none'}"/><div class="xh"><div class="xi" style="background:rgba(148,163,184,.18);color:#cbd5e1"><span class="mso" style="font-size:13px">edit</span></div><div class="xl">编辑</div><button class="xr" @pointerdown.stop @click.stop="run"><span class="mso">play_arrow</span></button></div><div class="xb" @mousedown.stop><textarea class="xi2 xi3" :value="data.editPrompt" placeholder="编辑提示词..." @input="cs.updateNodeData(p.id,{editPrompt:($event.target as any).value})"/><img v-if="data.imageUrl" :src="data.imageUrl" class="xi4"/></div><Handle type="source" :position="Position.Right" :style="{background:'#94a3b8',width:10,height:10,border:'none'}"/></div></template>
<style scoped>.x{width:240px;border:2px solid var(--border);border-radius:12px;background:var(--paper);box-shadow:var(--jc-shadow-sm);color:var(--ink1)}.x.sel{border-color:var(--olive-dark)}.xh{display:flex;align-items:center;gap:8px;padding:8px 12px;border-bottom:1px solid var(--border2)}.xi{width:24px;height:24px;border-radius:6px;display:flex;align-items:center;justify-content:center}.xl{flex:1;font-size:13px;font-weight:600}.xr{width:26px;height:26px;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--ink2);cursor:pointer;display:flex;align-items:center;justify-content:center}.xb{padding:10px;display:flex;flex-direction:column;gap:6px}.xi2{width:100%;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--ink1);padding:5px 8px;font-size:11px;outline:none;font:inherit}.xi3{min-height:48px;resize:vertical}.xi4{width:100%;max-height:120px;border-radius:4px;object-fit:contain;background:#0003;display:block}</style>
